import { Injectable } from "@angular/core";
import { CommonHttpModule } from "../../providers/commonHttpModule";
import { map, Observable } from "rxjs";
import { Disbursment, DisbursmentDetails } from "./client-approval-list.component.modal";

@Injectable({
    providedIn: "root"
})
export class ClientService {


    constructor(private http: CommonHttpModule) { }


    // method to get the data from db
    getDisbursementData(params: any): Observable<{ data: Disbursment[]; total_count: number }> {
        return this.http.post<{ total_count: number, data: Disbursment[] }>("client_disbursement_tracker_approval_pending", params)
            .pipe(
                map(response => ({
                    total_count: response.total_count,
                    data: response.data
                }))
            );
    }
}