import { Component, inject, OnDestroy } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { LoaderService } from '../../shared/loader/loader.service';
import { MatFormFieldModule, MatLabel } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { FormsModule } from '@angular/forms';
import { LoaderComponent } from '../../shared/loader/loader.component';
import { CommonModule } from '@angular/common';
import { columnsToDisplay, DisbursmentDetails } from './client-approval-list.component.modal';
import { Disbursment } from './../disbursment/disbursment.component.model';
import { DisbursDtlsCompComponent } from './../disbursment/disburs-dtls-comp/disburs-dtls-comp.component';
import { SnackbarService } from '../../shared/snack-bar/snack-bar.service';
import { MatDialog, } from '@angular/material/dialog';
import { Router } from '@angular/router';
import { ClientService } from './client-approval-list.component.service';
import { Subject } from 'rxjs';
import { debounceTime } from 'rxjs/operators';


@Component({
  selector: 'app-disbursment',
  standalone: true,
  imports: [MatTableModule, MatButtonModule, MatIconModule,
    MatFormFieldModule, MatInputModule,
    CommonModule, MatLabel, FormsModule, LoaderComponent, DisbursDtlsCompComponent
  ],
  templateUrl: './client-approval-list.component.html',
  styleUrl: './client-approval-list.component.css'
})
export class ClientApprovalListComponent implements OnDestroy {
  loader = inject(LoaderService);
  isLoading = this.loader.loading;
  searchTerm: string = '';
  allDataLoaded = false;
  datasource: MatTableDataSource<any> = new MatTableDataSource<any>([]);
  columnsToDisplay = columnsToDisplay;
  columnsToDisplayOnly = this.columnsToDisplay.map(col => col.property);
  expandedElement: Disbursment | null = null;
  disbursementdetails: DisbursmentDetails = new DisbursmentDetails({});
  isExpandedVal: boolean = false;

  currentPage = 1;
  pageSize = 30;
  totalCount = 0;
  private searchSubject = new Subject<string>();

  constructor(private clientService: ClientService, private snackbar: SnackbarService, private dialog: MatDialog, private router: Router) {
    this.searchSubject
      .pipe(
        debounceTime(1000)
      )
      .subscribe(() => {
        this.onSearch();
      });
  }
  ngOnInit() {
    this.getDisbursmentDataFromDb(true);
  }

  ngOnDestroy() {
    this.searchSubject.complete();
  }

  inputSearch(): void {
    this.searchSubject.next(this.searchTerm);
  }
  /** Fetches disbursement data from the database. */
  getDisbursmentDataFromDb(reset: boolean) {
    if (reset) {
      this.currentPage = 1;
      this.datasource.data = [];
      this.totalCount = 0;
      this.allDataLoaded = false;
    }
    const body: any = {
      query: this.searchTerm.trim(),
      page: this.currentPage,
      page_size: this.pageSize
    }
    this.loader.show();
    this.clientService.getDisbursementData(body).subscribe({
      next: (response) => {
        this.totalCount = response.total_count;
        this.datasource.data = [
          ...this.datasource.data,
          ...response.data.map(item => ({
            ...item,
            eta: item.eta ? item.eta.split("T")[0] : '',
            etd: item.etd ? item.etd.split("T")[0] : ''
          }))
        ];
        if (this.datasource.data.length >= this.totalCount) {
          this.allDataLoaded = true;
        }

        this.currentPage++;
        this.loader.hide();
      },
      error: (error) => {
        console.error('Error fetching disbursement data:', error);
        this.loader.hide();
      }
    });
  }


  onClick(element: any) {
    sessionStorage.setItem("disbursement_seq", element.disbursement_seq);
    const pdaOrFda = element.status?.slice(0, 3);
    sessionStorage.setItem("pdaOrFda", pdaOrFda);
    this.router.navigate(['/layout/client-approval-form'], {
    });
  }


  // method to search the record globally
  onSearch() {
    this.getDisbursmentDataFromDb(true);
  }

  // method to  clear the search term
  clearSearch() {
    this.searchTerm = '';
    this.getDisbursmentDataFromDb(true);
  }


  // method to call the api on scroll
  onManualScroll(): void {
    const scrollContainer = document.querySelector('.table-container');
    if (scrollContainer && !this.isExpandedVal) {
      const scrollPosition = scrollContainer.scrollTop + scrollContainer.clientHeight;
      const scrollHeight = scrollContainer.scrollHeight;
      if (
        scrollPosition >= scrollHeight - 10 &&
        !this.loader.loading() &&
        !this.allDataLoaded
      ) {
        // get api for disbursment data
        this.getDisbursmentDataFromDb(false);
      }
    }
  }
}



